#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int C, L;
        scanf("%d %d", &C, &L);
        int max_change = L;
        for (int i = 1; i <= C; i++) {
            if (C - i >= L) {
                max_change = i;
            } else {
                break;
            }
        }
        printf("%d\n", max_change);
    }
    return 0;
}

