import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int C = sc.nextInt();
            int L = sc.nextInt();
            int max_change = L;
            for (int i = 1; i <= C; i++) {
                if (C - i >= L) {
                    max_change = i;
                } else {
                    break;
                }
            }
            System.out.println(max_change);
        }
    }
}

